const checkpoints = [];

const lists = JSON.parse(localStorage.getItem('saved_lists') || '[]');
const items = JSON.parse(localStorage.getItem('saved_list_items') || '[]');
const publications = JSON.parse(localStorage.getItem('publications') || '[]');

// Find the 'Thesis Sources' reading list
const thesisList = (Array.isArray(lists) ? lists : []).find(
  (l) => l && l.listType === 'reading_list' && typeof l.name === 'string' && l.name.trim().toLowerCase() === 'thesis sources'
);

// Compute qualifying RL journal articles (2019–2023, >=50 citations, RL-related)
const topicKeyword = 'reinforcement learning';
const minYear = 2019;
const maxYear = 2023;
const minCitations = 50;

let qualifyingPubs = (Array.isArray(publications) ? publications : []).filter((p) => {
  if (!p || p.publicationType !== 'journal_article') return false;
  if (typeof p.year !== 'number' || p.year < minYear || p.year > maxYear) return false;
  if (typeof p.citationCount !== 'number' || p.citationCount < minCitations) return false;
  const kw = Array.isArray(p.keywords) ? p.keywords.map((k) => (k || '').toLowerCase()) : [];
  const topics = Array.isArray(p.topics) ? p.topics.map((t) => (t || '').toLowerCase()) : [];
  const title = (p.title || '').toLowerCase();
  const abstract = (p.abstract || '').toLowerCase();
  const tk = topicKeyword.toLowerCase();
  const hasTopic = kw.includes(tk) || topics.includes(tk) || title.includes(tk) || abstract.includes(tk);
  return hasTopic;
});

// Sort qualifying publications by citations_high_to_low (then year desc)
qualifyingPubs.sort((a, b) => {
  const citA = typeof a.citationCount === 'number' ? a.citationCount : 0;
  const citB = typeof b.citationCount === 'number' ? b.citationCount : 0;
  if (citA !== citB) return citB - citA;
  const yearA = typeof a.year === 'number' ? a.year : 0;
  const yearB = typeof b.year === 'number' ? b.year : 0;
  return yearB - yearA;
});

const top3 = qualifyingPubs.slice(0, 3).map((p) => p.id);

let thesisListPubIds = [];
if (thesisList) {
  thesisListPubIds = (Array.isArray(items) ? items : [])
    .filter((it) => it && it.listId === thesisList.id && it.itemType === 'publication')
    .map((it) => it.itemId);
}

// CP1 (0.3): List named 'Thesis Sources' exists as a reading_list
checkpoints.push({ passed: !!thesisList, weight: 0.3 });

// CP2 (0.3): List has exactly 3 items and every item is a qualifying RL journal article in 2019–2023 with >=50 citations
const allItemsQualify = !!(thesisList && thesisListPubIds.length === 3 && thesisListPubIds.every((id) => qualifyingPubs.some((p) => p.id === id)));
checkpoints.push({ passed: allItemsQualify, weight: 0.3 });

// CP3 (0.4): The list contains exactly the top-3 most-cited qualifying publications
const hasTop3 = !!(thesisList && top3.length === 3 && thesisListPubIds.length === 3 && top3.every((id) => thesisListPubIds.includes(id)));
checkpoints.push({ passed: hasTop3, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const publications = JSON.parse(localStorage.getItem('publications') || '[]');
const notes = JSON.parse(localStorage.getItem('notes') || '[]');

// Find most recent conference paper about graph neural networks
const topic = 'graph neural network';
let gnnConfs = (Array.isArray(publications) ? publications : []).filter((p) => {
  if (!p || p.publicationType !== 'conference_paper') return false;
  const kw = Array.isArray(p.keywords) ? p.keywords.map((k) => (k || '').toLowerCase()) : [];
  const topics = Array.isArray(p.topics) ? p.topics.map((t) => (t || '').toLowerCase()) : [];
  const title = (p.title || '').toLowerCase();
  const abstract = (p.abstract || '').toLowerCase();
  const tk = topic.toLowerCase();
  const hasTopic = kw.includes(tk) || topics.includes(tk) || title.includes(tk) || abstract.includes(tk);
  return hasTopic;
});

gnnConfs.sort((a, b) => {
  const yearA = typeof a.year === 'number' ? a.year : 0;
  const yearB = typeof b.year === 'number' ? b.year : 0;
  if (yearA !== yearB) return yearB - yearA;
  const ca = a.createdAt ? new Date(a.createdAt).getTime() : 0;
  const cb = b.createdAt ? new Date(b.createdAt).getTime() : 0;
  return cb - ca;
});

const latest = gnnConfs[0];

let noteWithCitation = null;
let noteWithCitationAndTitle = null;
let linkedNote = null;

if (latest && Array.isArray(notes)) {
  const targetCitation = (latest.apaCitation || '').trim();
  for (const n of notes) {
    if (!n || typeof n.content !== 'string') continue;
    if (n.content.trim() === targetCitation) {
      noteWithCitation = noteWithCitation || n;
      const title = (n.title || '').trim().toLowerCase();
      if (title === 'gnn latest conference paper') {
        noteWithCitationAndTitle = n;
      }
      if (n.relatedPublicationId === latest.id) {
        linkedNote = n;
      }
    }
  }
}

// CP1 (0.4): A note exists whose content matches the APA citation of the latest GNN conference paper
checkpoints.push({ passed: !!(latest && noteWithCitation), weight: 0.4 });

// CP2 (0.3): That citation note is titled 'GNN latest conference paper'
checkpoints.push({ passed: !!noteWithCitationAndTitle, weight: 0.3 });

// CP3 (0.3): A citation note is linked to the correct publication via relatedPublicationId
checkpoints.push({ passed: !!(latest && linkedNote && linkedNote.relatedPublicationId === latest.id), weight: 0.3 });

return checkoints = checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const projects = JSON.parse(localStorage.getItem('projects') || '[]');
const bookmarks = JSON.parse(localStorage.getItem('bookmarks') || '[]');
const bookmarkFolders = JSON.parse(localStorage.getItem('bookmark_folders') || '[]');

// Reproduce searchProjects('climate modeling') behavior (default sort funding_high_to_low)
const qLower = 'climate modeling';
let results = (Array.isArray(projects) ? projects.slice() : []);

results = results.filter((p) => {
  if (!p) return false;
  const t = (p.title || '').toLowerCase();
  const st = (p.shortTitle || '').toLowerCase();
  const d = (p.description || '').toLowerCase();
  const kwArr = Array.isArray(p.topicKeywords) ? p.topicKeywords.map((k) => (k || '').toLowerCase()) : [];
  const kwMatch = kwArr.some((k) => k.includes(qLower));
  return t.includes(qLower) || st.includes(qLower) || d.includes(qLower) || kwMatch;
});

results.sort((a, b) => {
  const fa = typeof a.fundingAmount === 'number' ? a.fundingAmount : 0;
  const fb = typeof b.fundingAmount === 'number' ? b.fundingAmount : 0;
  const sa = a.startDate ? new Date(a.startDate).getTime() : 0;
  const sb = b.startDate ? new Date(b.startDate).getTime() : 0;
  if (fb !== fa) return fb - fa;
  return sb - sa;
});

const firstTwo = results.slice(0, 2);
const qualifyingAmongTwo = firstTwo.filter((p) => typeof p.teamMemberCount === 'number' && p.teamMemberCount >= 4);

let targetProject = null;
if (qualifyingAmongTwo.length > 0) {
  targetProject = qualifyingAmongTwo.slice().sort((a, b) => {
    const fa = typeof a.fundingAmount === 'number' ? a.fundingAmount : 0;
    const fb = typeof b.fundingAmount === 'number' ? b.fundingAmount : 0;
    return fb - fa;
  })[0];
}

// Find the 'Potential collaborations' folder
const targetFolder = (Array.isArray(bookmarkFolders) ? bookmarkFolders : []).find(
  (f) => f && typeof f.name === 'string' && f.name.trim().toLowerCase() === 'potential collaborations'
);

let hasBookmarkForTarget = false;
let hasBookmarkInFolder = false;

if (targetProject && Array.isArray(bookmarks)) {
  const projectBookmarks = bookmarks.filter((bm) => bm && bm.itemType === 'project' && bm.itemId === targetProject.id);
  hasBookmarkForTarget = projectBookmarks.length > 0;
  if (targetFolder) {
    hasBookmarkInFolder = projectBookmarks.some((bm) => bm.folderId === targetFolder.id);
  }
}

// CP1 (0.5): The higher-funded qualifying project among the first two results is bookmarked
checkpoints.push({ passed: !!(targetProject && hasBookmarkForTarget), weight: 0.5 });

// CP2 (0.5): That bookmark is in a folder named 'Potential collaborations'
checkpoints.push({ passed: !!(targetProject && targetFolder && hasBookmarkInFolder), weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const lists = JSON.parse(localStorage.getItem('saved_lists') || '[]');
const items = JSON.parse(localStorage.getItem('saved_list_items') || '[]');
const courses = JSON.parse(localStorage.getItem('courses') || '[]');

// Qualifying courses: Spring 2025, graduate, credits >= 3
let qualifyingCourses = (Array.isArray(courses) ? courses : []).filter((c) => {
  if (!c) return false;
  if (c.termSeason !== 'spring') return false;
  if (typeof c.termYear !== 'number' || c.termYear !== 2025) return false;
  if (c.level !== 'graduate') return false;
  if (typeof c.credits !== 'number' || c.credits < 3) return false;
  return true;
});

qualifyingCourses.sort((a, b) => {
  const na = typeof a.courseNumber === 'number' ? a.courseNumber : 0;
  const nb = typeof b.courseNumber === 'number' ? b.courseNumber : 0;
  if (na !== nb) return na - nb;
  return 0;
});

const topTwoIds = qualifyingCourses.slice(0, 2).map((c) => c.id);

// Find 'Courses to Take 2025' course_list
const targetList = (Array.isArray(lists) ? lists : []).find(
  (l) => l && l.listType === 'course_list' && typeof l.name === 'string' && l.name.trim().toLowerCase() === 'courses to take 2025'
);

let listCourseIds = [];
if (targetList) {
  listCourseIds = (Array.isArray(items) ? items : [])
    .filter((it) => it && it.listId === targetList.id && it.itemType === 'course')
    .map((it) => it.itemId);
}

// CP1 (0.3): List named 'Courses to Take 2025' exists as a course_list
checkpoints.push({ passed: !!targetList, weight: 0.3 });

// CP2 (0.3): The list has exactly 2 courses, each matching the Spring 2025 grad >=3 credits criteria
const allListCoursesQualify = !!(targetList && listCourseIds.length === 2 && listCourseIds.every((id) => qualifyingCourses.some((c) => c.id === id)));
checkpoints.push({ passed: allListCoursesQualify, weight: 0.3 });

// CP3 (0.4): The two courses in the list are exactly the lowest-numbered qualifying courses
const hasCorrectTwo = !!(targetList && topTwoIds.length === 2 && listCourseIds.length === 2 && topTwoIds.every((id) => listCourseIds.includes(id)));
checkpoints.push({ passed: hasCorrectTwo, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const events = JSON.parse(localStorage.getItem('events') || '[]');
const lists = JSON.parse(localStorage.getItem('saved_lists') || '[]');
const listItems = JSON.parse(localStorage.getItem('saved_list_items') || '[]');
const reminders = JSON.parse(localStorage.getItem('event_reminders') || '[]');

const now = new Date();
const sixMonthsLater = new Date(now.getTime());
sixMonthsLater.setMonth(sixMonthsLater.getMonth() + 6);

let candidates = (Array.isArray(events) ? events : []).filter((e) => {
  if (!e) return false;
  const start = e.startDateTime ? new Date(e.startDateTime) : null;
  if (!start) return false;
  if (start < now || start > sixMonthsLater) return false;
  if (e.accessType !== 'public') return false;
  if (e.isCanceled) return false;
  const city = (e.locationCity || '').toLowerCase();
  const isNY = city === 'new york';
  const isOnline = e.locationType === 'online';
  return isNY || isOnline;
});

candidates.sort((a, b) => {
  const sa = a.startDateTime ? new Date(a.startDateTime).getTime() : 0;
  const sb = b.startDateTime ? new Date(b.startDateTime).getTime() : 0;
  return sa - sb;
});

const targetEvent = candidates[0];

// 'Attend' lists
const attendLists = (Array.isArray(lists) ? lists : []).filter(
  (l) => l && l.listType === 'event_attend_list' && typeof l.name === 'string' && l.name.trim().toLowerCase() === 'attend'
);
const attendListIds = new Set(attendLists.map((l) => l.id));

let inAttendList = false;
if (targetEvent) {
  inAttendList = (Array.isArray(listItems) ? listItems : []).some(
    (it) => it && it.itemType === 'event' && it.itemId === targetEvent.id && attendListIds.has(it.listId)
  );
}

// CP1 (0.5): The earliest qualifying event is added to an 'Attend' list
checkpoints.push({ passed: !!(targetEvent && inAttendList), weight: 0.5 });

// CP2 (0.5): There is a reminder for that event with reminderOffsetDays === 3
let hasReminder3Days = false;
if (targetEvent) {
  hasReminder3Days = (Array.isArray(reminders) ? reminders : []).some(
    (r) => r && r.eventId === targetEvent.id && r.reminderOffsetDays === 3
  );
}
checkpoints.push({ passed: !!(targetEvent && hasReminder3Days), weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const requests = JSON.parse(localStorage.getItem('contact_requests') || '[]');
const slots = JSON.parse(localStorage.getItem('availability_slots') || '[]');

// Find earliest available Wednesday slot fully between 10:00 and 12:00 UTC
let wednesdaySlots = (Array.isArray(slots) ? slots : []).filter((s) => {
  if (!s || !s.isAvailable || s.dayOfWeek !== 'wednesday') return false;
  const start = s.startDateTime ? new Date(s.startDateTime) : null;
  const end = s.endDateTime ? new Date(s.endDateTime) : null;
  if (!start || !end) return false;
  const sh = start.getUTCHours();
  const sm = start.getUTCMinutes();
  const eh = end.getUTCHours();
  const em = end.getUTCMinutes();
  const startMinutes = sh * 60 + sm;
  const endMinutes = eh * 60 + em;
  const windowStart = 10 * 60; // 10:00
  const windowEnd = 12 * 60;   // 12:00
  return startMinutes >= windowStart && endMinutes <= windowEnd;
});

wednesdaySlots.sort((a, b) => {
  const sa = a.startDateTime ? new Date(a.startDateTime).getTime() : 0;
  const sb = b.startDateTime ? new Date(b.startDateTime).getTime() : 0;
  return sa - sb;
});

const targetSlot = wednesdaySlots[0];

// Requests from Alex Rivera as prospective PhD student with appropriate subject and ML mention
const matchingRequests = (Array.isArray(requests) ? requests : []).filter((r) => {
  if (!r) return false;
  const nameOk = (r.name || '').trim() === 'Alex Rivera';
  const emailOk = (r.email || '').trim().toLowerCase() === 'alex.rivera@example.edu';
  const subjectOk = (r.subject || '').trim() === 'PhD Supervision Inquiry for Fall 2026';
  const reasonOk = r.reason === 'prospective_phd_student';
  const msg = (r.message || '').toLowerCase();
  const messageNonEmpty = (r.message || '').length > 0;
  const messageHasML = msg.includes('machine learning');
  return nameOk && emailOk && subjectOk && reasonOk && messageNonEmpty && messageHasML;
});

// CP1 (0.4): At least one such well-formed request from Alex Rivera exists
checkpoints.push({ passed: matchingRequests.length > 0, weight: 0.4 });

// CP2 (0.6): Such a request selected the earliest eligible Wednesday 10:00–12:00 slot
let hasCorrectSlot = false;
if (targetSlot && matchingRequests.length > 0) {
  hasCorrectSlot = matchingRequests.some(
    (r) => r.preferredSlotId === targetSlot.id && r.preferredStartDateTime === targetSlot.startDateTime
  );
}
checkpoints.push({ passed: !!(targetSlot && hasCorrectSlot), weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const settingsRaw = localStorage.getItem('profile_settings');
const settings = settingsRaw ? JSON.parse(settingsRaw) : null;
const tagline = settings && typeof settings.tagline === 'string' ? settings.tagline : '';
const keywords = settings && Array.isArray(settings.primaryResearchKeywords) ? settings.primaryResearchKeywords : [];

// CP1 (0.4): Tagline mentions machine learning, scientific discovery, and a speed-related concept
let taglineOk = false;
if (tagline) {
  const tl = tagline.toLowerCase();
  const hasML = tl.includes('machine learning');
  const hasSciDisc = tl.includes('scientific discovery');
  const hasSpeedConcept = tl.includes('faster') || tl.includes('speed') || tl.includes('accelerat');
  taglineOk = hasML && hasSciDisc && hasSpeedConcept;
}
checkpoints.push({ passed: taglineOk, weight: 0.4 });

// CP2 (0.6): Exactly three primary keywords: reinforcement learning, causal inference, scientific discovery
let keywordsOk = false;
if (Array.isArray(keywords) && keywords.length === 3) {
  const lower = keywords.map((k) => (k || '').toLowerCase().trim());
  const unique = Array.from(new Set(lower));
  const required = ['reinforcement learning', 'causal inference', 'scientific discovery'];
  const allPresent = required.every((req) => lower.includes(req));
  keywordsOk = unique.length === 3 && allPresent;
}
checkpoints.push({ passed: keywordsOk, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const settingsRaw = localStorage.getItem('profile_settings');
const settings = settingsRaw ? JSON.parse(settingsRaw) : null;
const publications = JSON.parse(localStorage.getItem('publications') || '[]');

// CP1 (0.4): Display preferences set to 5 publications sorted by citations_high_to_low
const displayOk = !!(settings && settings.publicationsDisplayCount === 5 && settings.publicationsSortOrder === 'citations_high_to_low');
checkpoints.push({ passed: displayOk, weight: 0.4 });

// CP2 (0.6): Featured publication is from 2022 or later and is uniquely featured
let featuredOk = false;
if (settings && settings.featuredPublicationId) {
  const featured = (Array.isArray(publications) ? publications : []).find((p) => p && p.id === settings.featuredPublicationId) || null;
  if (featured && typeof featured.year === 'number' && featured.year >= 2022) {
    const featuredFlags = (Array.isArray(publications) ? publications : []).filter((p) => p && p.isFeatured);
    if (featuredFlags.length === 0 || (featuredFlags.length === 1 && featuredFlags[0].id === featured.id)) {
      featuredOk = true;
    }
  }
}
checkpoints.push({ passed: featuredOk, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
